// ══ RIGHT PANEL ══
function renderRight(data) {
  const total = data.length;
  const dom = field => dominant(countBy(data,field));
  const [pS,nS] = dom('SEDE');
  const [pG,nG] = dom('GENERACION');
  const [pGn,nGn] = dom('GENERO');
  const [pJ,nJ] = dom('NIVEL_JERARQUIA');
  const [pE,nE] = dom('EMPRESA');
  const [pA,nA] = dom('ADMINISTRADORA DE NOMINA');
  // Antigüedad predominante
  const antigMap = {};
  data.forEach(r=>{ const ra=getRangoAntig(r); if(ra){antigMap[ra]=(antigMap[ra]||0)+1;} });
  const [pAnt,nAnt] = dominant(antigMap);
  setText('prSede',     pS);  setText('prSedeSub',    `${nS} personas · ${pct(nS,total)}`);
  setText('prGen',      pG.replace('GENERACION ','GEN ')); setText('prGenSub',`${nG} personas · ${pct(nG,total)}`);
  setText('prGenero',   pGn==='H'?'HOMBRE':'MUJER'); setText('prGeneroSub',`${nGn} personas · ${pct(nGn,total)}`);
  setText('prJer',      pJ);  setText('prJerSub',     `${nJ} personas · ${pct(nJ,total)}`);
  setText('prEmp',      pE);  setText('prEmpSub',     `${nE} personas · ${pct(nE,total)}`);
  setText('prAdmin',    pA);  setText('prAdminSub',   `${nA} personas · ${pct(nA,total)}`);
  setText('prAntig',    pAnt||'–'); setText('prAntigSub', pAnt?`${nAnt} personas · ${pct(nAnt,total)}`:'');
  buildTable('tSede',  countBy(data,'SEDE'),total);
  buildTable('tGen',   countBy(data,'GENERACION'),total,k=>k.replace('GENERACION ','GEN '));
  buildTable('tJer',   countBy(data,'NIVEL_JERARQUIA'),total);
  buildTable('tEmp',   countBy(data,'EMPRESA'),total);
  buildTable('tAdmin', countBy(data,'ADMINISTRADORA DE NOMINA'),total);
  buildTable('tAntig', antigMap, total);
}
function buildTable(id,counts,total,labelFn) {
  const sorted = Object.entries(counts).sort((a,b)=>b[1]-a[1]);
  document.getElementById(id).innerHTML =
    '<thead><tr><th>Nombre</th><th>N</th><th>%</th></tr></thead><tbody>' +
    sorted.map(([k,v])=>`<tr><td>${labelFn?labelFn(k):k}</td><td>${v}</td><td class="pct">${pct(v,total)}</td></tr>`).join('') +
    `<tr class="tot"><td>Total</td><td>${total}</td><td>100%</td></tr></tbody>`;
}

// ══ EXPORT PDF ══
async function exportPDF() {
  const btn = document.getElementById('pdfBtn');
  btn.innerHTML = '⏳ Generando...'; btn.disabled = true;
  const savedTheme = theme;
  try {
    const {jsPDF} = window.jspdf;
    // Ocultar topbar entero durante captura
    const topbar = document.getElementById('topbar');
    topbar.style.display = 'none';
    document.documentElement.classList.add('no-trans');
    theme = 'light';
    document.documentElement.setAttribute('data-theme','light');
    setLogos(); rebuildAll();
    await new Promise(r=>setTimeout(r,700));
    // Forzar que el scroll-area muestre TODO su contenido para la captura
    const el = document.getElementById('scroll');
    const origOverflow = el.style.overflow;
    const origHeight = el.style.height;
    el.style.overflow = 'visible';
    el.style.height = 'auto';
    await new Promise(r=>setTimeout(r,200));
    const canvas = await html2canvas(el,{
      scale:1.8, useCORS:true, logging:false,
      backgroundColor:'#EEF2F7',
      width: el.scrollWidth,
      height: el.scrollHeight,
      windowWidth: el.scrollWidth,
      windowHeight: el.scrollHeight,
      scrollX: 0, scrollY: 0
    });
    el.style.overflow = origOverflow;
    el.style.height = origHeight;
    topbar.style.display = '';
    theme = savedTheme;
    document.documentElement.setAttribute('data-theme',theme==='light'?'light':'');
    document.documentElement.classList.remove('no-trans');
    document.getElementById('themeLbl').textContent = theme==='dark'?'Claro':'Oscuro';
    setLogos(); rebuildAll();
    const pdf = new jsPDF({orientation:'landscape',unit:'mm',format:'a4'});
    const pw=pdf.internal.pageSize.getWidth();   // 297mm
    const ph=pdf.internal.pageSize.getHeight();  // 210mm
    const mg=12;
    const uw=pw-mg*2;  // 273mm área útil
    const uh=ph-mg*2;  // 186mm área útil
    const ratio=uw/canvas.width;  // escala para ajustar al ancho
    let srcY=0, page=0;
    while(srcY<canvas.height){
      if(page>0) pdf.addPage();
      const sliceH = Math.min(uh/ratio, canvas.height-srcY);
      const sc=document.createElement('canvas');
      sc.width=canvas.width;
      sc.height=Math.ceil(sliceH);
      const sctx=sc.getContext('2d');
      sctx.fillStyle='#EEF2F7';
      sctx.fillRect(0,0,sc.width,sc.height);
      sctx.drawImage(canvas,0,srcY,canvas.width,sliceH,0,0,canvas.width,sliceH);
      pdf.addImage(sc.toDataURL('image/png'),'PNG',mg,mg,uw,sliceH*ratio);
      srcY+=sliceH; page++;
    }
    pdf.save(`MIRA_Dashboard_RH_${new Date().toISOString().slice(0,10)}.pdf`);
  } catch(err){
    console.error(err); alert('Error al generar PDF: '+err.message);
    theme=savedTheme;
    document.documentElement.setAttribute('data-theme',theme==='light'?'light':'');
    setLogos(); rebuildAll();
  } finally {
    btn.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="12" y1="18" x2="12" y2="12"/><line x1="9" y1="15" x2="15" y2="15"/></svg> Exportar PDF';
    btn.disabled=false;
  }
}

