// ═══════════════════════════ DRAG & DROP KPIs ═══════════════════════════
function initKpiDrag() {
  const grid = document.getElementById('krow');
  if (!grid || grid._dragInit) return;
  grid._dragInit = true;
  let dragSrc = null;

  grid.addEventListener('dragstart', e => {
    const card = e.target.closest('.kcard[draggable="true"]');
    if (!card) return;
    dragSrc = card;
    card.classList.add('dragging');
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', '');
  });
  grid.addEventListener('dragend', e => {
    grid.querySelectorAll('.kcard').forEach(c => c.classList.remove('dragging','drag-over'));
    dragSrc = null;
  });
  grid.addEventListener('dragover', e => {
    e.preventDefault();
    const card = e.target.closest('.kcard[draggable="true"]');
    grid.querySelectorAll('.kcard').forEach(c => c.classList.remove('drag-over'));
    if (card && card !== dragSrc) card.classList.add('drag-over');
  });
  grid.addEventListener('drop', e => {
    e.preventDefault();
    const card = e.target.closest('.kcard[draggable="true"]');
    if (!card || !dragSrc || card === dragSrc) return;
    card.classList.remove('drag-over');
    const parent = card.parentNode;
    const srcNext = dragSrc.nextElementSibling;
    const tgtNext = card.nextElementSibling;
    if (srcNext === card) { parent.insertBefore(card, dragSrc); }
    else if (tgtNext === dragSrc) { parent.insertBefore(dragSrc, card); }
    else {
      const ph = document.createElement('div');
      parent.insertBefore(ph, dragSrc);
      parent.insertBefore(dragSrc, tgtNext);
      parent.insertBefore(card, ph);
      parent.removeChild(ph);
    }
  });
}

// ═══════════════════════════ DRAG & DROP CHARTS ═══════════════════════════
function initChartDrag() {
  const scroll = document.getElementById('scroll');
  if (!scroll || scroll._dragInit) return;
  scroll._dragInit = true;
  let dragSrc = null;

  scroll.addEventListener('dragstart', e => {
    const card = e.target.closest('.card[draggable="true"]');
    if (!card) return;
    dragSrc = card;
    setTimeout(() => card.classList.add('dragging'), 0);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', '');
  });
  scroll.addEventListener('dragend', e => {
    scroll.querySelectorAll('.card').forEach(c => c.classList.remove('dragging','drag-over'));
    dragSrc = null;
  });
  scroll.addEventListener('dragover', e => {
    e.preventDefault();
    const card = e.target.closest('.card[draggable="true"]');
    scroll.querySelectorAll('.card').forEach(c => c.classList.remove('drag-over'));
    if (card && card !== dragSrc) card.classList.add('drag-over');
  });
  scroll.addEventListener('dragleave', e => {
    const card = e.target.closest('.card[draggable="true"]');
    if (card) card.classList.remove('drag-over');
  });
  scroll.addEventListener('drop', e => {
    e.preventDefault();
    const card = e.target.closest('.card[draggable="true"]');
    if (!card || !dragSrc || card === dragSrc) return;
    card.classList.remove('drag-over');
    // También manejar r2 (filas de 2) como bloque
    const srcBlock = dragSrc.closest('.r2') || dragSrc;
    const tgtBlock = card.closest('.r2') || card;
    if (srcBlock === tgtBlock) return;
    const parent = srcBlock.parentNode;
    const tgtNext = tgtBlock.nextElementSibling;
    if (tgtNext === srcBlock) { parent.insertBefore(srcBlock, tgtBlock); }
    else {
      const ph = document.createElement('div');
      parent.insertBefore(ph, srcBlock);
      parent.insertBefore(srcBlock, tgtNext);
      parent.insertBefore(tgtBlock, ph);
      parent.removeChild(ph);
    }
    // Re-render charts to fit new positions
    setTimeout(() => { Object.values(charts).forEach(c => { try{c.resize();}catch(e){} }); }, 50);
  });
}

